import{_ as a,c as r,o as t,aj as i}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Iroha 3","description":"","frontmatter":{},"headers":[],"relativePath":"get-started/index.md","filePath":"get-started/index.md","lastUpdated":1777621302000}'),o={name:"get-started/index.md"};function s(l,e,h,n,d,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="iroha-3" tabindex="-1">Iroha 3 <a class="header-anchor" href="#iroha-3" aria-label="Permalink to &quot;Iroha 3&quot;">​</a></h1><p>Iroha 3 is the Nexus-oriented deployment track shipped from the main Hyperledger Iroha workspace. It keeps the same core building blocks as Iroha 2 while adding the Nexus model for data spaces, multi-lane execution, and SORA-specific deployment profiles.</p><p>At a high level, Iroha 3 combines:</p><ul><li>deterministic execution and storage</li><li>the Iroha Virtual Machine (IVM) for portable smart contracts</li><li>Norito as the canonical wire format</li><li>Torii for client, operator, and app-facing APIs</li><li>Sumeragi consensus with operator telemetry and status endpoints</li></ul><h2 id="quickstart" tabindex="-1">Quickstart <a class="header-anchor" href="#quickstart" aria-label="Permalink to &quot;Quickstart&quot;">​</a></h2><p>If you are starting from scratch, follow these pages in order:</p><ol><li><a href="/iroha-2-docs/get-started/install-iroha-2.html">Install Iroha 3</a></li><li><a href="/iroha-2-docs/get-started/launch-iroha-2.html">Launch Iroha 3</a></li><li><a href="/iroha-2-docs/get-started/operate-iroha-2-via-cli.html">Operate Iroha 3 via CLI</a></li><li><a href="/iroha-2-docs/get-started/sora-nexus-dataspaces.html">Connect to SORA Nexus dataspaces</a></li><li><a href="/iroha-2-docs/get-started/private-dataspace-fee-sponsor.html">Sponsor private dataspace fees</a></li></ol><p>If you are migrating an existing deployment or mental model, read <a href="/iroha-2-docs/get-started/iroha-2.html">Iroha 3 vs. Iroha 2</a> first.</p><h2 id="sdks" tabindex="-1">SDKs <a class="header-anchor" href="#sdks" aria-label="Permalink to &quot;SDKs&quot;">​</a></h2><p>The current SDK entry points documented in this site are:</p><ul><li><a href="/iroha-2-docs/guide/tutorials/rust.html">Rust</a></li><li><a href="/iroha-2-docs/guide/tutorials/python.html">Python</a></li><li><a href="/iroha-2-docs/guide/tutorials/javascript.html">JavaScript / TypeScript</a></li><li><a href="/iroha-2-docs/guide/tutorials/kotlin-java.html">Android, Kotlin, and Java</a></li><li><a href="/iroha-2-docs/guide/tutorials/swift.html">Swift and iOS</a></li></ul><h2 id="operator-references" tabindex="-1">Operator References <a class="header-anchor" href="#operator-references" aria-label="Permalink to &quot;Operator References&quot;">​</a></h2><p>The pages you will use most often while running a network are:</p><ul><li><a href="/iroha-2-docs/reference/binaries.html">Working with Iroha binaries</a></li><li><a href="/iroha-2-docs/reference/genesis.html">Genesis reference</a></li><li><a href="/iroha-2-docs/reference/torii-endpoints.html">Torii endpoints</a></li><li><a href="/iroha-2-docs/get-started/sora-nexus-dataspaces.html">Connect to SORA Nexus dataspaces</a></li><li><a href="/iroha-2-docs/get-started/private-dataspace-fee-sponsor.html">Sponsor private dataspace fees</a></li><li><a href="/iroha-2-docs/reference/compatibility-matrix.html">Compatibility matrix</a></li></ul><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><ul><li><a href="https://github.com/hyperledger-iroha/iroha/tree/i23-features" target="_blank" rel="noreferrer">Iroha <code>i23-features</code> branch</a></li><li><a href="https://github.com/hyperledger-iroha/iroha/blob/i23-features/docs/README.md" target="_blank" rel="noreferrer">Workspace docs index</a></li><li><a href="https://github.com/hyperledger-iroha/iroha/blob/i23-features/docs/source/iroha_3_whitepaper.md" target="_blank" rel="noreferrer">Iroha 3 whitepaper</a></li><li><a href="https://github.com/hyperledger-iroha/iroha/blob/i23-features/docs/source/iroha_2_whitepaper.md" target="_blank" rel="noreferrer">Iroha 2 whitepaper</a></li></ul>',16)])])}const f=a(o,[["render",s]]);export{u as __pageData,f as default};
